          </span>
          {issues.length > 0 ? (
            <span style={{ marginLeft: 'auto', fontSize: 10, opacity: 0.6 }}>
              Tab to cycle ({activeIssueIndex + 1}/{issues.length})
            </span>
          ) : null}
        </div>
        {issues.length > 0 ? (
          <ul
            data-testid="sketch-issue-list"
            style={{
              margin: 0,
              padding: 0,
              listStyle: 'none',
              display: 'flex',
              flexDirection: 'column',
              gap: 2,
            }}
          >
            {issues.map((issue, idx) => (
              <li
                key={`${issue.code}-${idx}`}
                data-testid={`sketch-issue-${idx}`}
                data-active={idx === activeIssueIndex ? 'true' : 'false'}
                style={{
                  fontSize: 11,
                  opacity: idx === activeIssueIndex ? 1 : 0.7,
                  fontWeight: idx === activeIssueIndex ? 600 : 400,
                }}
              >
                • {issue.message}
              </li>
            ))}
          </ul>
        ) : null}
      </div>

      {/* Bottom-centre toolbar */}
      <div
        data-testid="sketch-toolbar"
        style={{
          position: 'absolute',
          bottom: 16,
          left: '50%',
          transform: 'translateX(-50%)',
          display: 'flex',
          alignItems: 'center',
          gap: 6,
          padding: 6,
          borderRadius: 8,
          backgroundColor: 'rgba(15, 22, 28, 0.92)',
          boxShadow: '0 4px 14px rgba(0,0,0,0.25)',
        }}
      >
        <SketchToolButton
          label="Line"
          shortcut="L"
          active={tool === 'line'}
          onClick={() => {
            setTool('line');
            setPendingStart(null);
          }}
        />
        <SketchToolButton
          label="Rectangle"
          shortcut="R"
          active={tool === 'rectangle'}
          onClick={() => {
            setTool('rectangle');
            setPendingStart(null);
          }}
        />
        {canPickWalls ? (
          <>
            <SketchToolButton
              label="Pick Walls"
              shortcut="P"
              active={tool === 'pick'}
              onClick={() => {
                setTool('pick');
                setPendingStart(null);
              }}
              testId="sketch-tool-pick"
            />
            {tool === 'pick' && session ? (
              <OffsetModeChip
                mode={session.pickWallsOffsetMode}
                onChange={(m) => void handleOffsetModeChange(m)}
                disabled={busy}
              />
            ) : null}
          </>
        ) : null}
        <div style={{ width: 1, height: 20, backgroundColor: '#33424d', margin: '0 4px' }} />
        {canAutoClose ? (
          <button
            type="button"
            data-testid="sketch-auto-close"
            disabled={busy}
            onClick={() => void handleAutoClose()}
            style={{
              padding: '4px 10px',
              borderRadius: 6,
              border: '1px solid #fab86c',
              backgroundColor: 'transparent',
              color: '#fab86c',
              fontSize: 11,
              cursor: busy ? 'not-allowed' : 'pointer',
            }}
            title="Connect the two open endpoints with a single line"
          >
            Auto-close
          </button>
        ) : null}
        <button
          type="button"
          data-testid="sketch-finish"
          disabled={finishDisabled}
          onClick={() => void handleFinish()}
          title={
            finishDisabled && errorCount > 0
              ? `${errorCount} issue${errorCount === 1 ? '' : 's'}`
              : ''
          }
          style={{
            padding: '4px 12px',
            borderRadius: 6,
            border: 'none',
            backgroundColor: validation?.valid ? TURQUOISE : '#33424d',
            color: validation?.valid ? '#0d1216' : '#7c8a93',
            fontSize: 12,
            fontWeight: 600,
            cursor: validation?.valid && !busy ? 'pointer' : 'not-allowed',
          }}
        >
          Finish
        </button>
        <button
          type="button"
          data-testid="sketch-cancel"
          title="Cancel sketch (Esc)"
          onClick={() => void handleCancel()}
          style={{
            padding: '4px 12px',
            borderRadius: 6,
            border: '1px solid #33424d',
            backgroundColor: 'transparent',
            color: '#fab86c',
            fontSize: 12,
            cursor: 'pointer',
          }}
        >
          Cancel
        </button>
      </div>
    </div>
  );
}

